    blog_hidrolik_sistem_imalat_og_title: 'Schweißfertigung hydraulischer und pneumatischer Systeme',
    blog_hidrolik_sistem_imalat_tag: 'Hydraulik · Pneumatik',
    blog_hidrolik_sistem_imalat_h1: 'Schweißfertigung hydraulischer und pneumatischer Systeme',
    blog_hidrolik_sistem_imalat_read: '7 Min. Lesezeit',
    blog_hidrolik_sistem_imalat_author: 'ArmaWeld Engineering',
    blog_hidrolik_sistem_imalat_breadcrumb3: 'Hydrauliksysteme',
    blog_hidrolik_sistem_imalat_s0: '<p>Hydraulische und pneumatische Systeme sind das Rückgrat der Kraftübertragung in Bau- und Landmaschinen. <strong>Hydraulik-Schweißfertigung</strong> verlangt Druckfestigkeit, Dichtheit und Lebensdauer.</p>',
    blog_hidrolik_sistem_imalat_s1: '<h2>1. Hydraulikzylinder-Fertigung</h2><p>Die kritischen Nähte sind Kopf, Boden und Flansch. Werkstoffe: S355J2+N oder 27MnCrB5. WIG-Wurzel + MAG-Füllung. Prüfdruck 1,5× Betriebsdruck.</p>',
    blog_hidrolik_sistem_imalat_s2: '<h2>2. Tanks und Reservoire</h2><ul><li>Luft + Seifenwasser</li><li>Helium-Lecktest</li><li>Vakuumtest</li><li>PT</li></ul>',
    blog_hidrolik_sistem_imalat_s3: '<h2>3. Manifolds</h2><table class="data-table"><thead><tr><th>Teil</th><th>Verfahren</th><th>ZfP</th></tr></thead><tbody><tr><td>Zylinder</td><td>WIG + MAG</td><td>100% VT, 10% UT</td></tr><tr><td>Tank</td><td>MAG</td><td>100% VT, Lecktest</td></tr><tr><td>Manifold</td><td>WIG</td><td>100% VT, Drucktest</td></tr><tr><td>Rohr</td><td>WIG + MAG</td><td>100% VT, RT/UT</td></tr></tbody></table>',
    blog_hidrolik_sistem_imalat_s4: '<h2>4. ArmaWeld Hydraulik-Kompetenz</h2><p>Wir fertigen Hydrauliktanks, Zylinderkörper und Manifolds für OEMs. Druckprüfstände bis 250 bar.</p>',
